import { readFile } from "node:fs/promises"
import type { APIRoute } from "astro"
import { getCollection } from "astro:content"

export const prerender = true

const navigationPreamble = "Navigation: [/sitemap.md](/sitemap.md)\n\n"

export async function getStaticPaths() {
  const pages = await getCollection("pages")
  return Promise.all(
    pages
      .filter((page) => page.id !== "index")
      .map(async (page) => ({
        params: {
          page: page.id,
        },
        props: {
          source: await readPageSource(page.filePath),
        },
      }))
  )
}

async function readPageSource(filePath: string | undefined) {
  if (!filePath) {
    throw new Error("Expected content page entry to include a file path.")
  }

  return readFile(filePath, "utf-8")
}

export const GET: APIRoute = ({ props }) => {
  return new Response(`${navigationPreamble}${props.source}`, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
    },
  })
}

import { readFile } from "node:fs/promises"
import type { APIRoute } from "astro"
import { getEntry } from "astro:content"

export const prerender = true

const agentPreamble = `# Fulldev UI Agent Entry Point

Navigation: [/sitemap.md](/sitemap.md)

If you are an AI agent, treat this page as the entry point for Fulldev UI. Install the Fulldev skill first if your environment supports skills, then read the relevant Markdown pages before editing a project.

\`\`\`bash
npx -y skills add fulldotdev/ui --skill fulldev -y
\`\`\`

Start here:

- Install Fulldev UI: [/docs/installation.md](/docs/installation.md)
- Understand the project model: [/docs/introduction.md](/docs/introduction.md)
- Customize theme tokens: [/docs/theming.md](/docs/theming.md)
- Browse documentation sections: [/docs.md](/docs.md)
- Browse installable components: [/components.md](/components.md)
- Browse installable blocks: [/blocks.md](/blocks.md)
- Discover all pages: [/sitemap.md](/sitemap.md)
- Read registry metadata: [/r/registry.json](/r/registry.json)

Every documentation page has a Markdown version. Add \`.md\` to a page URL, for example \`/components/button.md\` or \`/blocks/hero.md\`.

Recommended agent flow:

1. Read \`/docs/installation.md\`.
2. Install the Fulldev skill if your agent supports skills.
3. Read the component or block page that matches the user's request.
4. Install registry items with \`npx shadcn@latest add @fulldev/<name>\`.
5. Use block and component examples as source references, not as hidden sidebar context.

---

## Homepage source

`

export const GET: APIRoute = async () => {
  const page = await getEntry("pages", "index")

  if (!page?.filePath) {
    return new Response(
      `${agentPreamble}No homepage content entry exists yet. Add \`src/content/pages/index.mdx\` to use this Markdown entry point.`,
      {
        headers: {
          "Content-Type": "text/plain; charset=utf-8",
        },
      }
    )
  }

  return new Response(
    `${agentPreamble}${await readFile(page.filePath, "utf-8")}`,
    {
      headers: {
        "Content-Type": "text/plain; charset=utf-8",
      },
    }
  )
}

import type { APIRoute } from "astro"
import { getCollection } from "astro:content"

import { getPageHref } from "@/lib/pages"

export const prerender = true

const getMarkdownHref = (href: string) =>
  href === "/" ? "/index.md" : `${href.replace(/\/$/, "")}.md`

export const GET: APIRoute = async () => {
  const pages = await getCollection("pages")
  const pageLinks = pages
    .map((page) => ({
      title: page.data.title,
      href: getPageHref(page),
      markdownHref: getMarkdownHref(getPageHref(page)),
      description: page.data.description,
    }))
    .sort((a, b) => a.href.localeCompare(b.href))

  const body = `# Fulldev UI Sitemap

Use the Markdown URLs when reading pages as an AI agent.

## Core

- [Agent entry point](/index.md)
- [Registry metadata](/r/registry.json)

## Pages

${pageLinks
  .map(
    (page) =>
      `- [${page.title}](${page.href}) | [Markdown](${page.markdownHref})${
        page.description ? ` - ${page.description}` : ""
      }`
  )
  .join("\n")}
`

  return new Response(body, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
    },
  })
}

import { type SchemaContext } from "astro:content"
import { z } from "astro/zod"

export const linkSchema = z.object({
  label: z.string(),
  href: z.string(),
})

export const buttonSchema = z.object({
  label: z.string(),
  href: z.string(),
  icon: z.string().optional(),
  variant: z.enum(["default", "outline", "secondary", "ghost"]).optional(),
})

export const imageSchema = ({ image }: SchemaContext) =>
  z.object({
    src: image(),
    alt: z.string(),
  })

export const seoSchema = (ctx: SchemaContext) =>
  z.object({
    title: z.string(),
    description: z.string(),
    image: imageSchema(ctx).optional(),
    canonical: z.string().optional(),
    noindex: z.boolean().optional(),
    nofollow: z.boolean().optional(),
  })

import { type SchemaContext } from "astro:content"
import { z } from "astro/zod"

import { buttonSchema, linkSchema } from "@/schemas/shared"

const nestedLinkSchema = linkSchema.extend({
  links: linkSchema.array().optional(),
})

export const globalSchema = ({ image }: SchemaContext) =>
  z.object({
    name: z.string(),
    logo: z
      .object({
        label: z.string(),
        href: z.string(),
        src: image().optional(),
        srcLight: image().optional(),
        srcDark: image().optional(),
        alt: z.string().optional(),
      })
      .refine((logo) => logo.src || (logo.srcLight && logo.srcDark), {
        message: "Logo must define src or both srcLight and srcDark.",
      }),
    header: z.object({
      navigation: nestedLinkSchema.array(),
      githubRepo: z.string(),
    }),
    sidebar: z.object({
      search: z.object({
        label: z.string(),
        empty: z.string(),
      }),
      navigation: nestedLinkSchema.array(),
    }),
    docs: z
      .object({
        callout: z.object({
          description: z.string(),
          button: buttonSchema,
        }),
      })
      .optional(),
  })

export type GlobalSchema = z.infer<ReturnType<typeof globalSchema>>

