import type { MarkdownHeading } from "astro"
import { getCollection } from "astro:content"

import type { GlobalSchema } from "@/schemas/global"
import type { DocSchema } from "@/schemas/layouts/doc"
import Base from "@/layouts/base.astro"
import DocBlock from "@/components/blocks/doc-1.astro"

type Props = {
  global: GlobalSchema
  page: DocSchema
  headings: MarkdownHeading[]
}

const props: Props = Astro.props
const currentPath = Astro.url.pathname
const globalCallout = props.global.docs?.callout
const markdownPath =
  currentPath === "/" ? "/index.md" : `${currentPath.replace(/\/$/, "")}.md`

const docsPages = await getCollection("pages")
const orderedDocLinks = [
  "docs/introduction",
  "docs/installation",
  "docs/theming",
  "docs/dark-mode",
  "docs/cli",
  "docs/mcp",
  "docs/skills",
  "components",
  "blocks",
  "docs/layouts",
]
  .map((id) => docsPages.find((entry) => entry.id === id))
  .filter((entry): entry is (typeof docsPages)[number] => Boolean(entry))
  .map((entry) => ({
    href: `/${entry.id}/`,
    title: entry.data.title,
  }))
const componentLinks = docsPages
  .filter(
    (entry) => entry.data.type === "doc" && entry.id.startsWith("components/")
  )
  .map((entry) => ({
    href: `/${entry.id}/`,
    title: entry.data.title,
    description: entry.data.description,
  }))
  .sort((a, b) => a.title.localeCompare(b.title))
const paginationLinks = [...orderedDocLinks, ...componentLinks]
const currentPageIndex = paginationLinks.findIndex(
  (item) => item.href === currentPath
)
const previousPage =
  currentPageIndex > 0 ? paginationLinks[currentPageIndex - 1] : undefined
const nextPage =
  currentPageIndex >= 0 ? paginationLinks[currentPageIndex + 1] : undefined
const currentDoc = await getCollection("pages", ({ data, id }) => {
  return data.type === "doc" && `/${id}/` === currentPath
})
const copySource = currentDoc[0]?.body
const copyButton = copySource
  ? {
      id: `docs-copy-page-${crypto.randomUUID()}`,
      source: copySource,
    }
  : undefined

const tocItems = props.headings
  .filter((heading) => heading.depth === 2 || heading.depth === 3)
  .map((heading) => ({
    depth: heading.depth,
    href: `#${heading.slug}`,
    label: heading.text,
  }))
---

<Base global={props.global} page={props.page}>
  <DocBlock
    title={props.page.title}
    description={props.page.description}
    copyButton={copyButton}
    markdownUrl={markdownPath}
    tocItems={tocItems}
    callout={globalCallout}
    previousPage={previousPage}
    nextPage={nextPage}
    labels={{
      copyMarkdown: "Copy Markdown",
      openIn: "Open in",
      openInMarkdown: "Open in Markdown",
      openInChatGPT: "Open in ChatGPT",
      openInClaude: "Open in Claude",
      openInCursor: "Open in Cursor",
      pagination: {
        previous: "Previous",
        next: "Next",
        ariaLabel: "Document pagination",
      },
      toc: "On This Page",
    }}
  >
    <slot />
  </DocBlock>
</Base>

